-- 2026-04-02 전체 종목 IR 정보 테이블 생성\nCREATE TABLE IF NOT EXISTS ir_info (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  stock_code TEXT NOT NULL,\n  title TEXT NOT NULL,\n  url TEXT NOT NULL,\n  published_at TIMESTAMP WITH TIME ZONE,\n  content TEXT,\n  source TEXT DEFAULT 'naver',\n  UNIQUE (stock_code, url)\n);\n\n-- 인덱스 최적화\nCREATE INDEX IF NOT EXISTS idx_ir_info_stock_code ON ir_info(stock_code);
